// Parse manual sync request (same payload as init-sync)
const body = $input.first().json.body || $input.first().json;
const operatorId = body.operator_id;
const connectionId = body.connection_id;
const hospitableCustomerId = body.hospitable_customer_id;
const hospitableConnectionId = body.hospitable_connection_id;

if (!operatorId || !hospitableCustomerId) {
  throw new Error('Missing operator_id or hospitable_customer_id');
}

return [{
  json: {
    operatorId,
    connectionId,
    hospitableCustomerId,
    hospitableConnectionId
  }
}];

// Upsert listings to Supabase
const response = $input.first().json;
const listings = response.data || response.listings || [];
const operatorId = $('Parse Manual Sync Payload').first().json.operatorId;
const hospitableCustomerId = $('Parse Manual Sync Payload').first().json.hospitableCustomerId;
const hospitableConnectionId = $('Parse Manual Sync Payload').first().json.hospitableConnectionId;

const supabaseUrl = "https://asazddtvjvmckouxcmmo.supabase.co";
const serviceKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImFzYXpkZHR2anZtY2tvdXhjbW1vIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzQxODQ2NCwiZXhwIjoyMDg4OTk0NDY0fQ.B7nmKCji4LEDU5JozanHl9PjNXzYuIpav6B8KR3BNV0";
const errors = [];
let upserted = 0;

for (const listing of listings) {
  const prop = {
    operator_id: operatorId,
    source: 'airbnb',
    status: 'completed',
    listing_status: 'listed',
    hospitable_property_id: listing.id || listing.listing_id,
    hospitable_connected: true,
    hospitable_last_sync_at: new Date().toISOString(),
    hospitable_sync_status: 'completed',
    hospitable_connection_id: hospitableConnectionId,
    hospitable_customer_id: hospitableCustomerId,
    public_title: listing.public_name || listing.name || listing.title || '',
    description: listing.description || listing.summary || '',
    property_type: listing.property_type || 'apartment',
    address: listing.address?.street || '',
    city: listing.address?.city || '',
    state: listing.address?.state || '',
    country: listing.address?.country_code || 'GB',
    postal_code: listing.address?.zipcode || '',
    lat: listing.address?.latitude || null,
    lng: listing.address?.longitude || null,
    max_guests: listing.capacity?.max || 4,
    images: listing.picture ? [{ url: listing.picture, caption: '', order: 0 }] : [],
    check_in_time: listing.check_in || '15:00',
    check_out_time: listing.check_out || '11:00',
    base_rate_amount: 100,
    base_rate_currency: 'GBP',
    minimum_stay: 1,
    cleaning_fee: { enabled: false }
  };

  const cleanFee = (listing.fees || []).find(f => f.name && f.name.includes('CLEANING'));
  if (cleanFee && cleanFee.fee) {
    prop.cleaning_fee = { enabled: true, amount: cleanFee.fee.amount / 100 };
  }

  const hpid = prop.hospitable_property_id;

  try {
    // Use this.helpers.httpRequest - the standard n8n Code node HTTP method
    const existing = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/nfs_properties?hospitable_property_id=eq.' + hpid + '&select=id',
      headers: {
        'apikey': serviceKey,
        'Authorization': 'Bearer ' + serviceKey,
        'Accept': 'application/json'
      }
    });

    if (Array.isArray(existing) && existing.length > 0) {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: supabaseUrl + '/rest/v1/nfs_properties?id=eq.' + existing[0].id,
        headers: {
          'apikey': serviceKey,
          'Authorization': 'Bearer ' + serviceKey,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: prop
      });
      upserted++;
    } else {
      await this.helpers.httpRequest({
        method: 'POST',
        url: supabaseUrl + '/rest/v1/nfs_properties',
        headers: {
          'apikey': serviceKey,
          'Authorization': 'Bearer ' + serviceKey,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: prop
      });
      upserted++;
    }
  } catch (err) {
    errors.push(hpid + ': ' + err.message);
  }
}

return [{ json: { propertiesUpserted: upserted, listingsReceived: listings.length, errors } }];
